    // 4. Dump intermediate unnormalized states directly to FP32 workspace
    #pragma unroll
    for (int j = 0; j < 8; ++j) {
        int base_idx = t * 64 * 16 * 512 + s * 16 * 512 + h * 512 + j * 64 + lane * 2;
        *reinterpret_cast<float2*>(&O_tmp[base_idx]) = make_float2(O_reg[j].x, O_reg[j].y);
    }

    if (lane == 0) {
        m_tmp[t * 16 * 64 + h * 64 + s] = m;
        l_tmp[t * 16 * 64 + h * 64 + s] = l;
    }

    // 5. Atomic Inter-Block Synchronization (Lock-Free)
    __threadfence(); // Guarantee global memory writes are visible
    __syncthreads(); // Wait for all threads in this block to finish writes

    __shared__ bool is_last_block;
    if (tid == 0) {
        // Atomic increment per token. The 64th block to arrive gets old==63
        int old = atomicAdd(&sync_counters[t], 1);
        is_last_block = (old == 63);
    }
    __syncthreads();

    // Only the mathematically guaranteed LAST block proceeds to the reduction phase
    if (!is_last_block) {
        return;
    }

    // 6. Final Global Reduction & FP32 -> BF16 Scaling (Last Block Only)
    // h = threadIdx.y (0 to 15), lane = threadIdx.x (0 to 31).
    // Each thread loads exactly 2 chunks out of the 64 total chunks.
    float m_chunk[2];
    float l_chunk[2];
    m_chunk[0] = m_tmp[t * 16 * 64 + h * 64 + lane];
    l_chunk[0] = l_tmp[t * 16 * 64 + h * 64 + lane];
    m_chunk[1] = m_tmp[t * 16 * 64 + h * 64 + lane + 32];
    l_chunk[1] = l_tmp[t * 16 * 64 + h * 64 + lane + 32];

    float m_max = fmaxf(m_chunk[0], m_chunk[1]);

    // Warp-level reduction to find exact global max across all 64 chunks
    float warp_m_max = m_max;
    #pragma unroll
    for (int offset = 16; offset > 0; offset /= 2) {
        warp_m_max = fmaxf(warp_m_max, __shfl_down_sync(0xffffffff, warp_m_max, offset));
