    if (m_chunk[1] != -INFINITY) l_sum = fmaf(l_chunk[1], expf(m_chunk[1] - warp_m_max), l_sum);

    // Warp-level reduction to find exact global sum
    float warp_l_sum = l_sum;
    #pragma unroll
    for (int offset = 16; offset > 0; offset /= 2) {
        warp_l_sum += __shfl_down_sync(0xffffffff, warp_l_sum, offset);
    }
    warp_l_sum = __shfl_sync(0xffffffff, warp_l_sum, 0);

    // Compute Base-2 LSE directly
    if (lane == 0) {
        if (warp_m_max == -INFINITY) {
            lse_ptr[t * 16 + h] = -INFINITY;
        } else {
            lse_ptr[t * 16 + h] = fmaf(warp_m_max, 1.4426950408889634f, log2f(warp_l_sum));
        }
    }

