    }
    float scale1 = 0.0f;
    if (warp_m_max != -INFINITY && warp_l_sum > 0.0f && m_chunk[1] != -INFINITY) {
        scale1 = expf(m_chunk[1] - warp_m_max) / warp_l_sum;
    }

    scale_smem[h * 64 + lane] = scale0;
    scale_smem[h * 64 + lane + 32] = scale1;
    __syncthreads(); // Ensure scale visibility

    // Final FP32 accumulation
    float out0[8] = {0};
    float out1[8] = {0};

    if (warp_m_max != -INFINITY && warp_l_sum > 0.0f) {
        #pragma unroll 8
        for (int s_idx = 0; s_idx < 64; ++s_idx) {
            float scale = scale_smem[h * 64 + s_idx];
            if (scale > 0.0f) {
                #pragma unroll
                for (int j = 0; j < 8; ++j) {
                    int d_idx = lane * 2 + j * 64;
                    int base_idx = t * 64 * 16 * 512 + s_idx * 16 * 512 + h * 512 + d_idx;
                    float2 val = *reinterpret_cast<const float2*>(&O_tmp[base_idx]);
                    out0[j] = fmaf(val.x, scale, out0[j]);
                    out1[j] = fmaf(val.y, scale, out1[j]);
                }
            }
        }
    }

    // Store back directly to final buffer using bfloat16
    #pragma unroll
    for (int j = 0; j < 8; ++j) {
        int d_idx = lane * 2 + j * 64;
        __nv_bfloat162 out_bf16 = __floats2bfloat162_rn(out0[j], out1[j]);
        *reinterpret_cast<__nv_bfloat162*>(&output_ptr[t * 16 * 512 + h * 512 + d_idx]) = out_bf16;
    }
}

